const serviceItems = $('Service List').all();
const resultItems = items;

const lines = [];

lines.push("📊 **YZEE Labs Daily Health Report**");
lines.push("");
lines.push(`🕒 Time: ${new Date().toLocaleString("en-US", { timeZone: "America/Santo_Domingo" })}`);
lines.push("");

for (let i = 0; i < serviceItems.length; i++) {
  const service = serviceItems[i].json;
  const result = resultItems[i]?.json || {};

  const name = service.name || "Unknown Service";
  const url = service.url || "No URL";

  const isDown = result.error !== undefined && result.error !== null;

  if (isDown) {
    const errorMessage = result.error.message || result.error || "Unknown error";
    lines.push(`🚨 **${name}**: DOWN`);
    lines.push(`   URL: ${url}`);
    lines.push(`   Error: ${errorMessage}`);
  } else {
    lines.push(`✅ **${name}**: Online`);
  }
}

lines.push("");
lines.push("🔗 Dashboard: http://10.0.0.67:3000");

return [
  {
    json: {
      content: lines.join("\n")
    }
  }
];
